  1→import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
  2→import { useLocation, useNavigate } from 'react-router-dom';
  3→import { learningApi } from '../api';
  4→import { API_BASE_URL, authFetch } from '../api/client';
  5→import AgentChatThread from '../components/agent/AgentChatThread';
  6→import AgentHubHeader from '../components/agent/AgentHubHeader';
  7→import AgentSessionPanel from '../components/agent/AgentSessionPanel';
  8→import ChatInput from '../components/agent/ChatInput';
  9→import SelectionAskChip from '../components/agent/SelectionAskChip';
 10→import { DEFAULT_HOME_ICON_KEY } from '../constants/homeIconCatalog';
 11→import { useAgent, useUser } from '../contexts';
 12→import useAgentControlOrchestrator from '../hooks/useAgentControlOrchestrator';
 13→import useCanvasPrecompute from '../hooks/useCanvasPrecompute';
 14→import useSelectionAskPrompt from '../hooks/useSelectionAskPrompt';
 15→import buildActionCatalog from '../utils/agent/buildActionCatalog';
 16→import buildUiSnapshot from '../utils/agent/buildUiSnapshot';
 17→import composeCanvasState from '../utils/agent/composeCanvasState';
 18→
 19→const SEARCH_TOGGLE_KEY = 'adelie_agent_web_search';
 20→const REVIEW_META_PREFIX = 'review_meta:';
 21→
 22→function readSearchToggleFromStorage(mode = 'home') {
 23→  try {
 24→    const value = localStorage.getItem(SEARCH_TOGGLE_KEY);
 25→    if (value === '1') return true;
 26→    if (value === '0') return false;
 27→    return mode === 'stock';
 28→  } catch {
 29→    return mode === 'stock';
 30→  }
 31→}
 32→
 33→function buildReviewTarget(mode, contextPayload) {
 34→  if (mode === 'home') {
 35→    const dateRaw = String(contextPayload?.date || '').replace(/\D/g, '');
 36→    const dateValue = Number(dateRaw);
 37→    if (dateRaw.length === 8 && Number.isFinite(dateValue)) {
 38→      return { contentType: 'briefing', contentId: dateValue };
 39→    }
 40→    return null;
 41→  }
 42→
 43→  const caseId = Number(contextPayload?.case_id || 0);
 44→  if (Number.isInteger(caseId) && caseId > 0) {
 45→    return { contentType: 'case', contentId: caseId };
 46→  }
 47→  return null;
 48→}
 49→
 50→function getContextByMode(mode) {
 51→  try {
 52→    if (mode === 'home') {
 53→      const enriched = sessionStorage.getItem('adelie_home_context_enriched');
 54→      if (enriched) return JSON.parse(enriched);
 55→      const base = sessionStorage.getItem('adelie_home_context');
 56→      return base ? JSON.parse(base) : null;
 57→    }
 58→    if (mode === 'education') {
 59→      const education = sessionStorage.getItem('adelie_education_context');
 60→      return education ? JSON.parse(education) : null;
 61→    }
 62→  } catch {
 63→    // ignore storage parsing error
 64→  }
 65→  return null;
 66→}
 67→
 68→function getVisibleSectionsByMode(mode) {
 69→  if (mode === 'stock') return ['portfolio_summary', 'holdings', 'stock_detail'];
 70→  if (mode === 'education') return ['calendar', 'daily_briefing', 'quiz_mission'];
 71→  if (mode === 'my') return ['profile', 'settings'];
 72→  return ['asset_summary', 'learning_schedule', 'issue_card', 'conversation_cards'];
 73→}
 74→
 75→function buildContextSummary(mode, contextPayload) {
 76→  if (mode === 'stock') {
 77→    const stockName = contextPayload?.stock_name || '선택 종목';
 78→    const stockCode = contextPayload?.stock_code ? ` (${contextPayload.stock_code})` : '';
 79→    const holdingText = contextPayload?.has_holding === undefined
 80→      ? ''
 81→      : contextPayload.has_holding ? ' · 보유 중' : ' · 미보유';
 82→    return `${stockName}${stockCode}${holdingText}`;
 83→  }
 84→  if (mode === 'education') {
 85→    return contextPayload?.selected_date
 86→      ? `${contextPayload.selected_date} 학습 기준`
 87→      : '교육 화면 컨텍스트';
 88→  }
 89→  return contextPayload?.market_summary || '홈 화면 컨텍스트';
 90→}
 91→
 92→function buildAgentContextEnvelope({ mode, pathname, contextPayload, userPrompt, searchEnabled = false }) {
 93→  const uiSnapshot = contextPayload?.ui_snapshot || buildUiSnapshot({
 94→    pathname,
 95→    mode,
 96→    visibleSections: getVisibleSectionsByMode(mode),
 97→    selectedEntities: {
 98→      stock_code: contextPayload?.stock_code || null,
 99→      stock_name: contextPayload?.stock_name || null,
100→      date_key: contextPayload?.selected_date || contextPayload?.date || null,
101→      case_id: contextPayload?.case_id || null,
102→    },
103→    filters: { tab: mode },
104→    portfolioSummary: contextPayload?.portfolio_summary || null,
105→  });
106→
107→  const actionCatalog = Array.isArray(contextPayload?.action_catalog)
108→    ? contextPayload.action_catalog
109→    : buildActionCatalog({ pathname, mode, stockContext: contextPayload });
110→
111→  return {
112→    mode,
113→    context: contextPayload,
114→    ui_snapshot: uiSnapshot,
115→    action_catalog: actionCatalog,
116→    interaction_state: {
117→      source: 'agent_canvas',
118→      mode,
119→      route: pathname,
120→      focused_prompt: userPrompt || null,
121→      search_enabled: Boolean(searchEnabled),
122→    },
123→  };
124→}
125→
126→export default function AgentCanvasPage() {
127→  const location = useLocation();
128→  const navigate = useNavigate();
129→  const { settings } = useUser();
130→  const {
131→    messages,
132→    assistantTurns,
133→    isLoading,
134→    isStreamingActive,
135→    canRegenerate,
136→    sessionId,
137→    sessions,
138→    refreshSessions,
139→    sendMessage,
140→    stopGeneration,
141→    regenerateLastResponse,
142→    setContextInfo,
143→    agentStatus,
144→    clearMessages,
145→    loadChatHistory,
146→  } = useAgent();
147→
148→  const [showContextInfo, setShowContextInfo] = useState(false);
149→  const [isSavingSession, setIsSavingSession] = useState(false);
150→  const [isSessionPanelOpen, setIsSessionPanelOpen] = useState(false);
151→  const [toast, setToast] = useState(null);
152→  const [isAtBottom, setIsAtBottom] = useState(true);
153→
154→  const processedPromptRef = useRef(new Set());
155→  const resetRef = useRef(new Set());
156→  const restoredSessionRef = useRef(new Set());
157→  const selectableContentRef = useRef(null);
158→
159→  const mode = location.state?.mode || (location.state?.stockContext ? 'stock' : 'home');
160→  const stockContext = mode === 'stock' ? (location.state?.stockContext || null) : null;
161→  const initialPrompt = location.state?.initialPrompt || '';
162→  const requestedSessionId = location.state?.sessionId || null;
163→  const useWebSearch = location.state?.useWebSearch ?? readSearchToggleFromStorage(mode);
164→
165→  const chatOptions = useMemo(
166→    () => ({
167→      useWebSearch: Boolean(useWebSearch),
168→      responseMode: 'canvas_markdown',
169→      structuredExtract: true,
170→    }),
171→    [useWebSearch],
172→  );
173→
174→  const contextPayload = useMemo(() => {
175→    if (location.state?.contextPayload) return location.state.contextPayload;
176→    if (mode === 'stock' && location.state?.stockContext) return location.state.stockContext;
177→    return getContextByMode(mode);
178→  }, [location.state, mode]);
179→
180→  // 사전 분석(precomputed) 로드
181→  const today = useMemo(() => new Date().toISOString().slice(0, 10), []);
182→  const { data: precomputed } = useCanvasPrecompute(mode, today);
183→
184→  const { executeAction, actionCatalog } = useAgentControlOrchestrator({
185→    mode,
186→    stockContext: stockContext || contextPayload,
187→  });
188→
189→  const buildContextInfoForPrompt = useCallback(
190→    (focusedPrompt = '') => {
191→      let ctxType = 'briefing';
192→      let ctxId = null;
193→
194→      if (mode === 'stock') {
195→        ctxType = 'case';
196→        ctxId = contextPayload?.case_id || null;
197→      } else if (mode === 'home') {
198→        const firstCaseId = contextPayload?.keywords?.[0]?.case_id;
199→        if (firstCaseId) {
200→          ctxType = 'case';
201→          ctxId = firstCaseId;
202→        }
203→      }
204→
205→      return {
206→        type: ctxType,
207→        id: ctxId,
208→        stepContent: JSON.stringify(
209→          buildAgentContextEnvelope({
210→            mode,
211→            pathname: location.pathname,
212→            contextPayload,
213→            userPrompt: focusedPrompt,
214→            searchEnabled: useWebSearch,
215→          }),
216→          null,
217→          2,
218→        ),
219→      };
220→    },
221→    [contextPayload, location.pathname, mode, useWebSearch],
222→  );
223→
224→  const activeSessionId = requestedSessionId || sessionId || null;
225→  const activeSessionMeta = useMemo(
226→    () => (Array.isArray(sessions) ? sessions.find((item) => item.id === activeSessionId) : null),
227→    [activeSessionId, sessions],
228→  );
229→  const isPinnedSession = Boolean(activeSessionMeta?.is_pinned);
230→  const contextSummary = useMemo(() => buildContextSummary(mode, contextPayload), [contextPayload, mode]);
231→
232→  // 턴 정규화 (스와이프 훅 대신 인라인)
233→  const turns = useMemo(() => {
234→    if (!Array.isArray(assistantTurns)) return [];
235→    return assistantTurns;
236→  }, [assistantTurns]);
237→
238→  // 사전 분석 콘텐츠를 첫 AI 메시지로 표시
239→  const welcomeTurn = useMemo(() => {
240→    if (turns.length > 0 || !precomputed?.analysis_md) return null;
241→    return {
242→      id: 'precomputed-welcome',
243→      userPrompt: '',
244→      assistantText: precomputed.analysis_md,
245→      status: 'done',
246→      uiActions: precomputed.ctas || [],
247→      sources: [],
248→      model: null,
249→      structured: null,
250→      guardrailNotice: null,
251→    };
252→  }, [turns.length, precomputed]);
253→
254→  const allTurns = useMemo(
255→    () => (welcomeTurn ? [welcomeTurn, ...turns] : turns),
256→    [welcomeTurn, turns],
257→  );
258→
259→  const lastTurn = allTurns.length > 0 ? allTurns[allTurns.length - 1] : null;
260→
261→  // 토스트 자동 클리어
262→  useEffect(() => {
263→    if (!toast) return;
264→    const timer = setTimeout(() => setToast(null), 2000);
265→    return () => clearTimeout(timer);
266→  }, [toast]);
267→
268→  // 리셋 처리
269→  useEffect(() => {
270→    if (!location.state?.resetConversation) return;
271→    if (resetRef.current.has(location.key)) return;
272→    resetRef.current.add(location.key);
273→    clearMessages();
274→  }, [clearMessages, location.key, location.state?.resetConversation]);
275→
276→  // 세션 복원
277→  useEffect(() => {
278→    if (!requestedSessionId) return;
279→    const restoreKey = `${location.key}:${requestedSessionId}`;
280→    if (restoredSessionRef.current.has(restoreKey)) return;
281→    restoredSessionRef.current.add(restoreKey);
282→    loadChatHistory(requestedSessionId).catch(() => {});
283→  }, [loadChatHistory, location.key, requestedSessionId]);
284→
285→  // 컨텍스트 설정
286→  useEffect(() => {
287→    const lastUserPrompt = lastTurn?.userPrompt || initialPrompt;
288→    setContextInfo(buildContextInfoForPrompt(lastUserPrompt));
289→    return () => { setContextInfo(null); };
290→  }, [buildContextInfoForPrompt, initialPrompt, lastTurn?.userPrompt, setContextInfo]);
291→
292→  const sendCanvasMessage = useCallback(
293→    (prompt) => {
294→      const normalized = String(prompt || '').trim();
295→      if (!normalized) return;
296→      sendMessage(normalized, settings?.difficulty || 'beginner', {
297→        chatOptions,
298→        contextInfoOverride: buildContextInfoForPrompt(normalized),
299→      });
300→    },
301→    [buildContextInfoForPrompt, chatOptions, sendMessage, settings?.difficulty],
302→  );
303→
304→  // 초기 프롬프트 전송
305→  useEffect(() => {
306→    const promptKey = `${location.key}:${initialPrompt}`;
307→    if (!initialPrompt || requestedSessionId || processedPromptRef.current.has(promptKey)) return;
308→    processedPromptRef.current.add(promptKey);
309→    sendCanvasMessage(initialPrompt);
310→  }, [initialPrompt, location.key, requestedSessionId, sendCanvasMessage]);
311→
312→  // 턴별 canvasState 빌더 (텍스트 선택 등에 사용)
313→  const buildCanvasStateForTurn = useCallback(
314→    (turn) =>
315→      composeCanvasState({
316→        messages,
317→        mode,
318→        contextPayload,
319→        aiStatus: agentStatus?.text,
320→        userPrompt: turn?.userPrompt || '',
321→        assistantText: turn?.assistantText || '',
322→        assistantTurn: turn,
323→      }),
324→    [agentStatus?.text, contextPayload, messages, mode],
325→  );
326→
327→  const canvasState = useMemo(
328→    () => buildCanvasStateForTurn(lastTurn),
329→    [buildCanvasStateForTurn, lastTurn],
330→  );
331→
332→  const reviewTarget = useMemo(
333→    () => buildReviewTarget(mode, contextPayload),
334→    [contextPayload, mode],
335→  );
336→
337→  const handleActionClick = useCallback(
338→    async (action) => {
339→      if (typeof action === 'string') {
340→        sendCanvasMessage(action);
341→        return;
342→      }
343→
344→      if (action?.type === 'tool' && action?.id) {
345→        const catalogEntry = actionCatalog.find((item) => item.id === action.id);
346→        const mergedAction = { ...(catalogEntry || {}), ...action };
347→        const result = await executeAction(mergedAction, { contextPayload });
348→        if (result?.ok && result?.result) {
349→          const summary = JSON.stringify(result.result, null, 2);
350→          sendCanvasMessage(
351→            `[Tool Result: ${action.label}]\n\`\`\`json\n${summary}\n\`\`\`\n위 결과를 바탕으로 설명해줘.`
352→          );
353→        }
354→        return;
355→      }
356→
357→      if (action?.type === 'navigate' && action?.id) {
358→        executeAction(action, { contextPayload });
359→        return;
360→      }
361→
362→      const nextPrompt = action?.prompt || action?.label || '';
363→      if (!nextPrompt) return;
364→      sendCanvasMessage(nextPrompt);
365→    },
366→    [actionCatalog, contextPayload, executeAction, sendCanvasMessage],
367→  );
368→
369→  const handleAskSelectedText = useCallback(
370→    (selectedText) => {
371→      const normalized = String(selectedText || '').trim();
372→      if (!normalized) return;
373→      const quotedPrompt = `다음 내용을 현재 맥락에서 설명해줘:\n"""${normalized}"""`;
374→      sendCanvasMessage(quotedPrompt);
375→    },
376→    [sendCanvasMessage],
377→  );
378→
379→  const {
380→    chip: selectionChip,
381→    handleAsk: handleAskSelection,
382→  } = useSelectionAskPrompt({
383→    containerRef: selectableContentRef,
384→    enabled: true,
385→    onAsk: handleAskSelectedText,
386→    minLength: 2,
387→    maxLength: 280,
388→  });
389→
390→  const handleBack = useCallback(() => {
391→    if (window.history.length > 1) {
392→      navigate(-1);
393→      return;
394→    }
395→    navigate('/home', { replace: true });
396→  }, [navigate]);
397→
398→  const openHistory = useCallback(() => {
399→    navigate('/agent/history', { state: { mode, contextPayload } });
400→  }, [contextPayload, mode, navigate]);
401→
402→  // 새 대화 핸들러
403→  const handleNewChat = useCallback(() => {
404→    clearMessages();
405→    setIsSessionPanelOpen(false);
406→    setToast('새 대화를 시작합니다');
407→  }, [clearMessages]);
408→
409→  // 세션 선택 핸들러
410→  const handleSelectSession = useCallback((selectedId) => {
411→    loadChatHistory(selectedId).catch(() => {});
412→    setIsSessionPanelOpen(false);
413→  }, [loadChatHistory]);
414→
415→  // 세션 삭제 핸들러
416→  const handleDeleteSession = useCallback(async (targetId) => {
417→    try {
418→      const response = await authFetch(`${API_BASE_URL}/api/v1/agent/sessions/${targetId}`, {
419→        method: 'DELETE',
420→      });
421→      if (response.ok) {
422→        await refreshSessions();
423→        if (targetId === activeSessionId) {
424→          clearMessages();
425→        }
426→        setToast('대화가 삭제되었습니다');
427→      }
428→    } catch {
429→      setToast('삭제에 실패했습니다');
430→    }
431→  }, [activeSessionId, clearMessages, refreshSessions]);
432→
433→  const handlePinSession = useCallback(async () => {
434→    if (!activeSessionId || isSavingSession) return;
435→    setIsSavingSession(true);
436→    try {
437→      const response = await authFetch(`${API_BASE_URL}/api/v1/agent/sessions/${activeSessionId}/pin`, {
438→        method: 'POST',
439→        headers: { 'Content-Type': 'application/json' },
440→        body: JSON.stringify({ pinned: true }),
441→      });
442→      if (!response.ok) throw new Error('pin_failed');
443→
444→      if (reviewTarget) {
445→        await learningApi.upsertProgress({
446→          content_type: reviewTarget.contentType,
447→          content_id: reviewTarget.contentId,
448→          status: 'viewed',
449→          progress_percent: 20,
450→        });
451→
452→        const titleCandidate = (
453→          contextPayload?.keywords?.[0]?.title
454→          || contextPayload?.case_title
455→          || contextPayload?.stock_name
456→          || lastTurn?.userPrompt
457→          || canvasState.title
458→          || '복습 카드'
459→        );
460→        const snippet = (lastTurn?.assistantText || '').replace(/\s+/g, ' ').trim().slice(0, 180);
461→        const iconKey = contextPayload?.keywords?.[0]?.icon_key || contextPayload?.icon_key || DEFAULT_HOME_ICON_KEY;
462→
463→        try {
464→          localStorage.setItem(
465→            `${REVIEW_META_PREFIX}${reviewTarget.contentType}:${reviewTarget.contentId}`,
466→            JSON.stringify({
467→              title: titleCandidate,
468→              icon_key: iconKey,
469→              last_summary_snippet: snippet,
470→              updated_at: new Date().toISOString(),
471→            }),
472→          );
473→        } catch {
474→          // ignore storage errors
475→        }
476→      }
477→
478→      await refreshSessions();
479→      setToast('이 대화를 홈/교육 복습 카드로 저장했어요.');
480→    } catch {
481→      setToast('대화 저장에 실패했어요. 잠시 후 다시 시도해 주세요.');
482→    } finally {
483→      setIsSavingSession(false);
484→    }
485→  }, [
486→    activeSessionId,
487→    canvasState.title,
488→    contextPayload,
489→    isSavingSession,
490→    lastTurn,
491→    refreshSessions,
492→    reviewTarget,
493→  ]);
494→
495→  const handleStopGeneration = useCallback(() => {
496→    stopGeneration();
497→  }, [stopGeneration]);
498→
499→  const handleRegenerate = useCallback(() => {
500→    if (canRegenerate) {
501→      regenerateLastResponse({
502→        difficulty: settings?.difficulty || 'beginner',
503→        chatOptions,
504→        contextInfoOverride: buildContextInfoForPrompt(lastTurn?.userPrompt || initialPrompt),
505→      }).catch(() => {});
506→      return;
507→    }
508→    if (lastTurn?.userPrompt) {
509→      sendCanvasMessage(lastTurn.userPrompt);
510→    }
511→  }, [
512→    canRegenerate,
513→    buildContextInfoForPrompt,
514→    chatOptions,
515→    initialPrompt,
516→    lastTurn,
517→    regenerateLastResponse,
518→    sendCanvasMessage,
519→    settings?.difficulty,
520→  ]);
521→
522→  // ChatInput 제출 핸들러
523→  const handleChatSubmit = useCallback((message, options) => {
524→    sendCanvasMessage(message);
525→  }, [sendCanvasMessage]);
526→
527→  // 추천 질문 클릭
528→  const handleSuggestedClick = useCallback((question) => {
529→    sendCanvasMessage(question);
530→  }, [sendCanvasMessage]);
531→
532→  const statusSubline = lastTurn?.model
533→    ? `${canvasState.aiStatus} · ${lastTurn.model}`
534→    : canvasState.aiStatus;
535→
536→  const followOutput = useCallback((atBottom) => {
537→    return atBottom ? 'smooth' : false;
538→  }, []);
539→
540→  return (
541→    <div className="flex min-h-screen flex-col bg-[var(--agent-bg-page,#F7F8FA)]">
542→      <AgentHubHeader
543→        title={canvasState.title}
544→        agentPhase={agentStatus?.phase}
545→        isStreamingActive={isStreamingActive}
546→        canRegenerate={canRegenerate}
547→        selectedUserPrompt={lastTurn?.userPrompt}
548→        isPinnedSession={isPinnedSession}
549→        isSavingSession={isSavingSession}
550→        activeSessionId={activeSessionId}
551→        showContextInfo={showContextInfo}
552→        contextSummary={contextSummary}
553→        statusSubline={statusSubline}
554→        onBack={handleBack}
555→        onStop={handleStopGeneration}
556→        onRegenerate={handleRegenerate}
557→        onPinSession={handlePinSession}
558→        onToggleContextInfo={() => setShowContextInfo((prev) => !prev)}
559→        onOpenHistory={openHistory}
560→        onNewChat={handleNewChat}
561→        onToggleSessionPanel={() => setIsSessionPanelOpen((prev) => !prev)}
562→        isSessionPanelOpen={isSessionPanelOpen}
563→      />
564→
565→      {/* 세션 패널 (헤더 아래 슬라이드-다운) */}
566→      <AgentSessionPanel
567→        sessions={sessions}
568→        activeSessionId={activeSessionId}
569→        onSelectSession={handleSelectSession}
570→        onDeleteSession={handleDeleteSession}
571→        isOpen={isSessionPanelOpen}
572→      />
573→
574→      {/* 채팅 스레드 (스크롤 컨테이너) */}
575→      <main
576→        className="flex-1 overflow-y-auto px-4 py-3"
577→        style={{ paddingBottom: 'calc(var(--bottom-nav-h,56px) + 120px)' }}
578→      >
579→        <AgentChatThread
580→          turns={allTurns}
581→          isLoading={isLoading}
582→          isStreamingActive={isStreamingActive}
583→          onActionClick={handleActionClick}
584→          contentRef={selectableContentRef}
585→          mode={mode}
586→          onSuggestedClick={handleSuggestedClick}
587→          onAtBottomChange={setIsAtBottom}
588→          followOutput={followOutput}
589→        />
590→      </main>
591→
592→      {/* 스크롤-투-바텀 FAB */}
593→      {!isAtBottom && allTurns.length > 0 && (
594→        <button
595→          type="button"
596→          onClick={() => {
597→            // Virtuoso의 scrollToIndex를 사용하려면 ref 필요
598→            // 대신 간단히 main element scroll
599→            const main = document.querySelector('main');
600→            if (main) main.scrollTo({ top: main.scrollHeight, behavior: 'smooth' });
601→          }}
602→          className="fixed bottom-[calc(var(--bottom-nav-h,56px)+130px)] right-4 z-20 flex h-10 w-10 items-center justify-center rounded-full bg-white shadow-lg active:scale-95"
603→          aria-label="최신 메시지로 이동"
604→        >
