 24→  if (mode === 'stock') return ['portfolio_summary', 'holdings', 'stock_detail'];
 25→  if (mode === 'education') return ['calendar', 'daily_briefing', 'quiz_mission'];
 26→  if (mode === 'my') return ['profile', 'settings'];
 27→  return ['asset_summary', 'learning_schedule', 'issue_card', 'conversation_cards'];
 28→}
 29→
 30→const SEARCH_TOGGLE_KEY = 'adelie_agent_web_search';
 31→
 32→function readSearchToggle(mode) {
 33→  try {
 34→    const value = localStorage.getItem(SEARCH_TOGGLE_KEY);
 35→    if (value === '1') return true;
 36→    if (value === '0') return false;
 37→    return mode === 'stock';
 38→  } catch {
 39→    return mode === 'stock';
 40→  }
 41→}
 42→
 43→export default function AgentDock() {
 44→  const { shouldHide, mode, placeholder, suggestedPrompt } = useAgentPromptHints();
 45→  const [input, setInput] = useState('');
 46→  const [inlineMessage, setInlineMessage] = useState(null);
 47→  const [isRouting, setIsRouting] = useState(false);
 48→  const [searchEnabled, setSearchEnabled] = useState(() => readSearchToggle(mode));
 49→  const [showSlashMenu, setShowSlashMenu] = useState(false);
 50→  const [slashQuery, setSlashQuery] = useState('');
 51→  const [activePrefix, setActivePrefix] = useState(null);
 52→  const location = useLocation();
 53→  const navigate = useNavigate();
 54→  const { messages, agentStatus, isStreamingActive } = useAgent();
 55→  const { keyboardOffset, shouldHideBottomNav } = useKeyboardInset();
 56→  const hasActiveSession = Array.isArray(messages) && messages.length > 0;
 57→  const isAgentRoute = location.pathname.startsWith('/agent');
 58→  const hideBottomNav = shouldHideBottomNav;
 59→
 60→  useEffect(() => {
 61→    try {
 62→      localStorage.setItem(SEARCH_TOGGLE_KEY, searchEnabled ? '1' : '0');
 63→    } catch {
 64→      // ignore storage errors
 65→    }
 66→  }, [searchEnabled]);
 67→
 68→  useEffect(() => {
 69→    try {
 70→      const hasStoredValue = localStorage.getItem(SEARCH_TOGGLE_KEY);
 71→      if (hasStoredValue === null) {
 72→        setSearchEnabled(mode === 'stock');
 73→      }
 74→    } catch {
 75→      setSearchEnabled(mode === 'stock');
 76→    }
 77→  }, [mode]);
 78→
 79→  useEffect(() => {
 80→    document.documentElement.style.setProperty('--keyboard-offset', `${keyboardOffset}px`);
 81→    return () => {
 82→      document.documentElement.style.setProperty('--keyboard-offset', '0px');
 83→    };
 84→  }, [keyboardOffset]);
 85→
 86→  const baseContextPayload = useMemo(() => {
 87→    if (mode === 'stock' && location.state?.stockContext) {
 88→      return location.state.stockContext;
 89→    }
 90→
 91→    if (mode === 'home') {
 92→      return readSessionJson('adelie_home_context');
 93→    }
 94→
 95→    if (mode === 'education') {
 96→      return readSessionJson('adelie_education_context');
 97→    }
 98→
 99→    return null;
100→  }, [location.state, mode]);
101→
102→  const {
103→    controlState,
104→    isAgentControlling,
105→    actionCatalog: orchestratorActionCatalog,
106→    executeAction,
107→    pendingAction,
108→    confirmPendingAction,
109→  } = useAgentControlOrchestrator({
110→    mode,
111→    stockContext: baseContextPayload,
112→  });
113→
114→  const actionCatalog = useMemo(
115→    () => buildActionCatalog({ pathname: location.pathname, mode, stockContext: baseContextPayload }),
116→    [baseContextPayload, location.pathname, mode],
117→  );
118→
119→  const buildControlContextPayload = useCallback((prompt = '') => {
120→    const uiSnapshot = buildUiSnapshot({
121→      pathname: location.pathname,
122→      mode,
123→      locationState: location.state || null,
124→      visibleSections: getVisibleSectionsByMode(mode),
125→      selectedEntities: {
126→        stock_code: baseContextPayload?.stock_code || null,
127→        stock_name: baseContextPayload?.stock_name || null,
128→        date_key: baseContextPayload?.date || null,
129→        case_id: baseContextPayload?.case_id || null,
130→      },
131→      filters: {
132→        tab: location.pathname.startsWith('/portfolio') ? 'portfolio' : mode,
133→      },
134→      portfolioSummary: baseContextPayload?.portfolio_summary || null,
135→    });
136→
137→    return {
138→      ...(baseContextPayload || {}),
139→      ui_snapshot: uiSnapshot,
140→      action_catalog: actionCatalog,
141→      interaction_state: {
142→        source: 'agent_dock',
143→        mode,
144→        route: location.pathname,
145→        last_prompt: prompt || null,
146→        search_enabled: searchEnabled,
147→        control_phase: controlState.phase,
148→        control_active: isAgentControlling,
149→      },
150→    };
151→  }, [actionCatalog, baseContextPayload, controlState.phase, isAgentControlling, location.pathname, location.state, mode, searchEnabled]);
152→
153→  const handleSlashCommand = useCallback((command) => {
154→    setShowSlashMenu(false);
155→    setSlashQuery('');
156→
157→    const action = command.action;
158→    if (action.type === 'navigate') {
159→      navigate(action.path, action.tab ? { state: { tab: action.tab } } : undefined);
160→    } else if (action.type === 'action') {
161→      const matchedAction = orchestratorActionCatalog.find((item) => item.id === action.actionId);
162→      if (matchedAction) {
163→        executeAction(matchedAction, { contextPayload: buildControlContextPayload('') });
164→      } else {
165→        setInlineMessage({ text: '현재 화면에서 사용할 수 없는 명령이에요.', canvasPrompt: null });
166→      }
167→    } else if (action.type === 'param') {
168→      if (action.prefix) {
169→        setActivePrefix({ label: command.desc, prefix: action.prefix });
170→        setInput('');
171→      }
172→      if (action.key === 'use_web_search') {
173→        setSearchEnabled(true);
174→      }
175→    }
176→  }, [navigate, orchestratorActionCatalog, executeAction, buildControlContextPayload]);
177→
178→  const submitPromptToCanvas = useCallback((prompt) => {
179→    const payload = buildControlContextPayload(prompt);
180→
181→    navigate('/agent', {
182→      state: {
183→        mode,
184→        initialPrompt: prompt.trim(),
185→        contextPayload: payload,
186→        useWebSearch: searchEnabled,
187→        resetConversation: location.pathname !== '/agent',
188→      },
189→    });
190→  }, [buildControlContextPayload, location.pathname, mode, navigate, searchEnabled]);
191→
192→  const routePrompt = useCallback(async (prompt, payload) => {
193→    const response = await authFetch(`${API_BASE_URL}/api/v1/agent/route`, {
194→      method: 'POST',
195→      headers: { 'Content-Type': 'application/json' },
196→      body: JSON.stringify({
197→        message: prompt,
198→        mode,
199→        context_text: JSON.stringify(payload),
200→        ui_snapshot: payload.ui_snapshot || null,
201→        action_catalog: payload.action_catalog || [],
202→        interaction_state: payload.interaction_state || null,
203→      }),
204→    });
205→    if (!response.ok) {
206→      throw new Error('route_failed');
207→    }
208→    return response.json();
209→  }, [mode]);
210→
211→  // /agent 페이지에서는 ChatInput이 대체하므로 숨김
212→  if (shouldHide || isAgentRoute) return null;
213→
214→  const phaseTextByPhase = {
215→    thinking: '에이전트 분석 중',
216→    tool_call: '도구 실행 중',
217→    answering: '답변 생성 중',
218→    stopped: '중단됨',
219→    notice: '답변 생성 중',
220→    error: '오류 발생',
221→    idle: '대기 중',
222→  };
223→  const isActivelyWorking = isStreamingActive || isAgentRoute;
224→  const dockStatusText = isAgentRoute
225→    ? (phaseTextByPhase[agentStatus?.phase] || phaseTextByPhase.idle)
226→    : '질문하세요';
227→  const shouldShowChevron = hasActiveSession && !isAgentRoute;
228→  const pulseActive = isRouting || isAgentControlling || isStreamingActive;
229→  const statusDotClass = pulseActive ? 'agent-status-dot-pulse' : '';
230→
231→  const submitPrompt = async (prompt) => {
232→    const raw = String(prompt || '').trim();
233→    const normalized = activePrefix ? `${activePrefix.prefix}${raw}` : raw;
234→    if (!normalized) return;
235→
236→    const controlPayload = buildControlContextPayload(normalized);
237→    setIsRouting(true);
238→    setInlineMessage(null);
239→
240→    try {
241→      const decision = await routePrompt(normalized, controlPayload);
242→      const nextDecision = decision?.decision;
243→
244→      if (nextDecision === 'inline_action') {
245→        const matchedAction = orchestratorActionCatalog.find((item) => item.id === decision?.action_id);
246→        if (!matchedAction) {
247→          setInlineMessage({
248→            text: '실행 가능한 액션을 찾지 못했어요.',
249→            canvasPrompt: normalized,
250→          });
251→        } else {
252→          await executeAction(matchedAction, {
253→            contextPayload: controlPayload,
254→            prompt: normalized,
255→          });
256→        }
257→      } else if (nextDecision === 'open_canvas' || nextDecision === 'open_chat') {
258→        submitPromptToCanvas(decision?.canvas_prompt || normalized);
259→      } else {
260→        setInlineMessage({
261→          text: decision?.inline_text || '자세히 보려면 캔버스를 열어주세요.',
262→          canvasPrompt: decision?.canvas_prompt || normalized,
263→        });
264→      }
265→    } catch {
266→      setInlineMessage({
267→        text: '자세한 분석은 캔버스에서 확인할 수 있어요.',
268→        canvasPrompt: normalized,
269→      });
270→    } finally {
271→      setIsRouting(false);
272→    }
273→
274→    setInput('');
275→    setActivePrefix(null);
276→  };
277→
278→  const handleSubmit = async (event) => {
279→    event.preventDefault();
280→    await submitPrompt(input || suggestedPrompt);
281→  };
282→
283→  const handleResumeChat = () => {
284→    navigate('/agent', {
285→      state: {
286→        mode,
287→        contextPayload: buildControlContextPayload(''),
288→        useWebSearch: searchEnabled,
289→      },
290→    });
291→  };
292→
293→  return (
294→    <div
295→      className="pointer-events-none fixed left-0 right-0 z-30 flex justify-center px-4 pb-2"
296→      style={{ bottom: `calc(${hideBottomNav ? '0px' : 'var(--bottom-nav-h,68px)'} + var(--keyboard-offset,0px))` }}
297→    >
298→      <div className="w-full max-w-mobile space-y-1.5">
299→        {/* 인라인 메시지 (트레이 대체 — 필요할 때만 노출) */}
300→        {inlineMessage?.text && (
301→          <div className="pointer-events-auto flex items-center justify-between gap-2 rounded-[14px] border border-[var(--agent-border,#E8EBED)] bg-white px-3 py-2 shadow-[var(--agent-shadow)]">
302→            <p className="min-w-0 truncate text-[12px] text-[#6B7684]">{inlineMessage.text}</p>
303→            {inlineMessage.canvasPrompt && (
304→              <button
305→                type="button"
306→                onClick={() => {
307→                  submitPromptToCanvas(inlineMessage.canvasPrompt);
308→                  setInlineMessage(null);
309→                }}
310→                className="flex-shrink-0 text-[12px] font-semibold text-[#FF6B00] active:opacity-70"
311→              >
312→                자세히
313→              </button>
314→            )}
315→          </div>
316→        )}
317→
318→        {/* 볼드 입력바 */}
319→        <AgentControlPulse active={pulseActive}>
320→          <div className="pointer-events-auto relative rounded-[20px] bg-white shadow-[0_-2px_12px_rgba(0,0,0,0.06)]">
321→            {/* 상단 상태 라인 (항상 노출) */}
322→            <div className="flex items-center gap-2 border-b border-[#F2F4F6] px-3 py-1.5">
323→              <button
324→                type="button"
325→                onClick={hasActiveSession ? handleResumeChat : undefined}
326→                className={`flex min-w-0 flex-1 items-center gap-2 text-left ${hasActiveSession ? 'active:bg-[#F7F8FA]' : ''}`}
327→              >
328→                <span className={`h-1.5 w-1.5 rounded-full ${
329→                  isActivelyWorking ? 'bg-[#1D6FDE]' : 'bg-[#16A34A]'
330→                } ${statusDotClass}`} />
331→                <div className="min-w-0">
332→                  <p className={`truncate text-[12px] font-medium ${isActivelyWorking ? 'text-[#4E5968]' : 'text-[#166534]'}`}>
333→                    {dockStatusText}
334→                  </p>
335→                </div>
336→                {shouldShowChevron && (
337→                  <svg className="ml-auto text-[#B0B8C1]" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
338→                    <path d="m9 18 6-6-6-6" />
339→                  </svg>
