341→              </button>
342→
343→              <div className="ml-auto flex items-center gap-1">
344→                <button
345→                  type="button"
346→                  onClick={() => setSearchEnabled((prev) => !prev)}
347→                  className={`flex h-8 w-8 flex-shrink-0 items-center justify-center rounded-full transition-colors ${
348→                    searchEnabled
349→                      ? 'bg-[#FFF2E8] text-[#FF6B00]'
350→                      : 'bg-[#F2F4F6] text-[#8B95A1]'
351→                  }`}
352→                  aria-label={searchEnabled ? '인터넷 검색 켜짐' : '인터넷 검색 꺼짐'}
353→                  title={searchEnabled ? '인터넷 검색: 켜짐' : '인터넷 검색: 꺼짐'}
354→                >
355→                  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.9" strokeLinecap="round" strokeLinejoin="round">
356→                    <circle cx="12" cy="12" r="9" />
357→                    <path d="M3 12h18" />
358→                    <path d="M12 3a15 15 0 0 1 0 18" />
359→                    <path d="M12 3a15 15 0 0 0 0 18" />
360→                  </svg>
361→                </button>
362→
363→                <button
364→                  type="button"
365→                  onClick={() => navigate('/agent/history', { state: { mode, contextPayload: buildControlContextPayload('') } })}
366→                  className="flex h-8 w-8 flex-shrink-0 items-center justify-center rounded-full bg-[#F2F4F6] text-[#6B7684] transition-colors active:bg-[#E8EBED]"
367→                  aria-label="대화 기록 보기"
368→                  title="대화 기록 보기"
369→                >
370→                  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.9" strokeLinecap="round" strokeLinejoin="round">
371→                    <path d="M12 8v5l3 2" />
372→                    <circle cx="12" cy="12" r="9" />
373→                  </svg>
374→                </button>
375→              </div>
376→            </div>
377→
378→            {showSlashMenu && (
379→              <SlashCommandMenu
380→                query={slashQuery}
381→                onSelect={handleSlashCommand}
382→                onClose={() => { setShowSlashMenu(false); setSlashQuery(''); }}
383→                visible={showSlashMenu}
384→              />
385→            )}
386→
387→            <form
388→              onSubmit={handleSubmit}
389→              className="flex h-12 items-center gap-2.5 px-3"
390→            >
391→              <button
392→                type="button"
393→                onClick={() => submitPrompt(suggestedPrompt)}
394→                className="flex h-7 w-7 flex-shrink-0 items-center justify-center rounded-full bg-[#FF6B00] text-white shadow-sm active:scale-95"
395→                aria-label="추천 질문 사용"
396→              >
397→                <svg width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
398→                  <path d="M12 3l2 5 5 2-5 2-2 5-2-5-5-2 5-2 2-5z" />
399→                  <path d="M19 4l.7 1.6 1.6.7-1.6.7-.7 1.6-.7-1.6-1.6-.7 1.6-.7.7-1.6z" />
400→                  <path d="M5.5 15l.7 1.6 1.6.7-1.6.7-.7 1.6-.7-1.6-1.6-.7 1.6-.7.7-1.6z" />
401→                </svg>
402→              </button>
403→
404→              <div className="flex min-w-0 flex-1 items-center gap-1.5">
405→                {activePrefix && (
406→                  <span className="inline-flex shrink-0 items-center gap-1 rounded-full border border-[#FF6B00]/20 bg-[#FFF2E8] px-2.5 py-1 text-[12px] font-semibold text-[#FF6B00]">
407→                    {activePrefix.label}
408→                    <button
409→                      type="button"
410→                      onClick={() => setActivePrefix(null)}
411→                      className="ml-0.5 text-[#FF6B00]/60 hover:text-[#FF6B00]"
