424→                    if (val.startsWith('/')) {
425→                      setShowSlashMenu(true);
426→                      setSlashQuery(val.slice(1));
427→                    } else {
428→                      setShowSlashMenu(false);
429→                      setSlashQuery('');
430→                    }
431→                  }}
432→                  onKeyDown={(e) => {
433→                    if (showSlashMenu && (e.key === 'ArrowUp' || e.key === 'ArrowDown' || e.key === 'Enter')) {
434→                      e.preventDefault();
435→                    }
436→                    if (e.key === 'Escape' && showSlashMenu) {
437→                      setShowSlashMenu(false);
438→                      setSlashQuery('');
439→                    }
440→                    if (e.key === 'Backspace' && !input && activePrefix) {
441→                      setActivePrefix(null);
442→                    }
443→                  }}
444→                  placeholder={activePrefix ? '내용을 입력하세요' : (input ? placeholder : suggestedPrompt)}
445→                  data-agent-dock-input
446→                  className="min-w-0 flex-1 bg-transparent text-[14px] text-[#191F28] placeholder:text-[#B0B8C1] focus:outline-none"
447→                  aria-label="에이전트 질문 입력"
448→                />
449→              </div>
450→
451→              <button
452→                type="submit"
453→                className="flex h-7 w-7 flex-shrink-0 items-center justify-center rounded-full bg-[#FF6B00] text-white shadow-sm active:scale-95"
454→                aria-label="질문 전송"
455→                disabled={isRouting}
456→              >
457→                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
458→                  <path d="m12 19V5" />
459→                  <path d="m5 12 7-7 7 7" />
