{"parentUuid":"09d33084-6df6-4b66-ad3c-971c62f188d3","isSidechain":true,"userType":"external","cwd":"/home/hj/2026/project/adelie-investment","sessionId":"0b4da217-d024-4b8f-abfb-93d987ec28ea","version":"2.1.50","gitBranch":"feature/canvas-agent-v4","agentId":"a82fa2b866203e799","slug":"transient-tumbling-wadler","message":{"model":"claude-opus-4-6","id":"REDACTED","type":"message","role":"assistant","content":[{"type":"tool_use","id":"REDACTED","name":"Write","input":{"file_path":"/home/hj/2026/project/adelie-investment/frontend/src/components/home/IssueCarousel.jsx","content":"import { useCallback, useEffect, useRef, useState } from 'react';
import ReactionButtons from '../common/ReactionButtons';
import { DEFAULT_HOME_ICON_KEY, getHomeIconSrc } from '../../constants/homeIconCatalog';
import { trackEvent } from '../../utils/analytics';

const ISSUE_AUTO_ADVANCE_MS = 4500;
const ISSUE_SWIPE_THRESHOLD_PX = 56;

/**
 * 오늘의 이슈 캐러셀 — 스와이프 + 자동재생 + 반응 버튼
 */
export default function IssueCarousel({
  issueCards,
  isLoadingKeywords,
  keywordError,
  marketSummary,
  todayDateKey,
  openAgentFromHome,
  selectableRef,
}) {
  const [activeIndex, setActiveIndex] = useState(0);
  const [autoPlayStopped, setAutoPlayStopped] = useState(false);
  const touchStartXRef = useRef(null);

  const activeCard = issueCards[activeIndex] || null;

  // 카드 수 변경 시 인덱스 보정
  useEffect(() => {
    if (issueCards.length === 0) {
      setActiveIndex(0);
      return;
    }
    setActiveIndex((prev) => Math.min(prev, issueCards.length - 1));
  }, [issueCards.length]);

  // 자동 재생
  useEffect(() => {
    if (issueCards.length < 2 || autoPlayStopped) return undefined;
    const intervalId = setInterval(() => {
      setActiveIndex((prev) => (prev + 1) % issueCards.length);
    }, ISSUE_AUTO_ADVANCE_MS);
    return () => clearInterval(intervalId);
  }, [autoPlayStopped, issueCards.length]);

  const stopAutoPlay = useCallback(() => {
    setAutoPlayStopped(true);
  }, []);

  const moveIssue = useCallback(
    (direction) => {
      if (issueCards.length < 2) return;
      stopAutoPlay();
      setActiveIndex((prev) => {
        const length = issueCards.length;
        return (prev + direction + length) % length;
      });
    },
    [issueCards.length, stopAutoPlay],
  );

  const handleTouchStart = useCallback((event) => {
    stopAutoPlay();
    touchStartXRef.current = event.changedTouches?.[0]?.clientX ?? null;
  }, [stopAutoPlay]);

  const handleTouchEnd = useCallback((event) => {
    if (touchStartXRef.current === null) return;
    const endX = event.changedTouches?.[0]?.clientX;
    const startX = touchStartXRef.current;
    touchStartXRef.current = null;
    if (typeof endX !== 'number') return;

    const deltaX = endX - startX;
    if (Math.abs(deltaX) < ISSUE_SWIPE_THRESHOLD_PX) return;
    if (deltaX > 0) moveIssue(-1);
    else moveIssue(1);
  }, [moveIssue]);

  return (
    <section>
      <div className="mb-3 flex items-center justify-between px-1">
        <h2 className="text-[24px] font-extrabold tracking-[-0.02em] text-[#101828]">오늘의 이슈</h2>
        <span className="text-xs font-semibold text-[#99a1af]">{formatKoreanDate(todayDateKey)}</span>
      </div>

      <div className="rounded-[26px] border border-[rgba(243,244,246,0.6)] bg-white p-6 shadow-[0_8px_32px_rgba(0,0,0,0.04)]">
        {isLoadingKeywords && (
          <p className="text-sm text-[#6a7282]">오늘의 이슈를 불러오는 중입니다...</p>
        )}

        {!isLoadingKeywords && keywordError && (
          <p className="text-sm text-red-500">{keywordError}</p>
        )}

        {!isLoadingKeywords && !keywordError && activeCard && (
          <>
            <div
              ref={selectableRef}
              className="relative"
              onTouchStart={handleTouchStart}
              onTouchEnd={handleTouchEnd}
              onMouseDown={stopAutoPlay}
            >
              {issueCards.length > 1 && (
                <button
                  type="button"
                  onClick={() => moveIssue(-1)}
                  className="absolute left-1 top-1/2 z-10 flex h-9 w-9 -translate-y-1/2 items-center justify-center rounded-full text-[#4E5968]/40 active:text-[#4E5968]/70"
                  aria-label="이전 이슈 보기"
                >
                  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                    <path d="m15 18-6-6 6-6" />
                  </svg>
                </button>
              )}

              {issueCards.length > 1 && (
                <button
                  type="button"
                  onClick={() => moveIssue(1)}
                  className="absolute right-1 top-1/2 z-10 flex h-9 w-9 -translate-y-1/2 items-center justify-center rounded-full text-[#4E5968]/40 active:text-[#4E5968]/70"
                  aria-label="다음 이슈 보기"
                >
                  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                    <path d="m9 18 6-6-6-6" />
                  </svg>
                </button>
              )}

              <div className="mb-5 flex items-start justify-between">
                <div className="flex items-center gap-3">
                  <div className="flex h-14 w-14 items-center justify-center rounded-[22px] bg-[rgba(255,118,72,0.1)]">
                    <img
                      src={getHomeIconSrc(activeCard.icon_key || DEFAULT_HOME_ICON_KEY)}
                      alt="이슈 아이콘"
                      className="h-9 w-9 object-contain"
                      onError={(event) => {
                        event.currentTarget.src = getHomeIconSrc(DEFAULT_HOME_ICON_KEY);
                      }}
                    />
                  </div>
                </div>
                <span className="rounded-full border border-[#f3f4f6] bg-[#f9fafb] px-3 py-1 text-[11px] font-bold text-[#6a7282]">
                  {activeCard.category || '오늘의 이슈'}
                </span>
              </div>

              <h3 className="text-[25px] font-extrabold leading-[1.28] tracking-[-0.02em] text-[#101828]">
                {activeCard.title}
              </h3>
              <p className="mt-3 text-[15px] leading-7 tracking-[-0.01em] text-[#6a7282]">
                {activeCard.description || marketSummary || '오늘 시장의 핵심 이슈를 함께 분석해봐요.'}
              </p>

              {issueCards.length > 1 && (
                <div className="mt-4 flex items-center justify-center gap-1.5">
                  {issueCards.map((item, index) => (
                    <button
                      key={`issue-dot-${item.id || item.title}-${index}`}
                      type="button"
                      onClick={() => {
                        stopAutoPlay();
                        setActiveIndex(index);
                      }}
                      className={`h-1.5 rounded-full transition-all ${index === activeIndex ? 'w-5 bg-[#FF6B00]' : 'w-1.5 bg-[#D1D6DB]'}`}
                      aria-label={`${index + 1}번 이슈로 이동`}
                    />
                  ))}
                </div>
              )}
            </div>

            <div className="mt-5 flex flex-wrap gap-2">
              <button
                type="button"
                onClick={() => openAgentFromHome(`${activeCard.title} 왜 중요한지 설명해줘`)}
                className="rounded-2xl bg-[#f2f4f6] px-4 py-2.5 text-[13px] font-bold text-[#4a5565]"
              >
                📉 {activeCard.title.slice(0, 16)}
              </button>
              <button
                type="button"
                onClick={() => openAgentFromHome('내 포트폴리오에 어떤 영향이 있는지 알려줘')}
                className="rounded-2xl bg-[#f2f4f6] px-4 py-2.5 text-[13px] font-bold text-[#4a5565]"
              >
                💼 내 포트폴리오 영향은?
              </button>
            </div>

            <div className="mt-4 flex items-center justify-between">
              <ReactionButtons contentType="keyword_card" contentId={activeCard.case_id || activeCard.title} />
              <button
                type="button"
                onClick={() => {
                  trackEvent('issue_card_click', { case_id: activeCard?.case_id, title: activeCard?.title });
                  openAgentFromHome(`${activeCard.title} 아델리와 알아보기`);
                }}
                className="rounded-2xl bg-primary px-5 py-2.5 text-sm font-semibold text-white"
              >
                아델리와 알아보기
              </button>
            </div>
          </>
        )}

        {!isLoadingKeywords && !keywordError && !activeCard && (
          <p className="text-sm text-[#6a7282]">표시할 이슈가 없습니다.</p>
        )}
      </div>
    </section>
  );
}

/* ── 헬퍼 ── */
function formatKoreanDate(dateKey) {
  if (!dateKey || dateKey.length !== 8) return '';
  return `${dateKey.slice(4, 6)}월 ${dateKey.slice(6, 8)}일`;
}
