  <h2 className="text-[18px] font-extrabold text-[#101828] mb-3 px-1">내 복습카드</h2>
  {isLoadingFlashCards ? (
    <p className="text-sm text-[#8B95A1] px-1">불러오는 중...</p>
  ) : (
    <FlashCardList cards={flashCards} onCardDeleted={handleFlashCardDeleted} />
  )}
</section>
```

