  1→/**
  2→ * Profile.jsx - 프로필/설정 화면
  3→ * 사용자 정보, 난이도 설정, 로그아웃
  4→ */
  5→import { useState } from 'react';
  6→import { useNavigate } from 'react-router-dom';
  7→import { useUser, DIFFICULTY_LEVELS } from '../contexts';
  8→import { motion } from 'framer-motion';
  9→import AppHeader from '../components/layout/AppHeader';
 10→
 11→/* ── 문의사항 컴포넌트 ── */
 12→function ContactSection() {
 13→  const [message, setMessage] = useState('');
 14→  const [submitted, setSubmitted] = useState(false);
 15→  const [submitting, setSubmitting] = useState(false);
 16→  const [submitError, setSubmitError] = useState(false);
 17→
 18→  const handleSubmit = async () => {
 19→    if (!message.trim()) return;
 20→    setSubmitting(true);
 21→    setSubmitError(false);
 22→    try {
 23→      const res = await fetch('/api/v1/feedback', {
 24→        method: 'POST',
 25→        headers: { 'Content-Type': 'application/json' },
 26→        body: JSON.stringify({ page: 'contact', rating: null, comment: message }),
 27→      });
 28→      if (!res.ok) throw new Error(`서버 오류: ${res.status}`);
 29→      setSubmitted(true);
 30→    } catch {
 31→      setSubmitError(true);
 32→    } finally {
 33→      setSubmitting(false);
 34→    }
 35→  };
 36→
 37→  if (submitted) {
 38→    return (
 39→      <div className="text-center py-4">
 40→        <img src="/images/penguin-3d.png" alt="Adelie" className="w-10 h-10 mx-auto mb-1" />
 41→        <p className="text-sm font-medium">문의가 접수되었습니다!</p>
 42→        <p className="text-xs text-text-secondary mt-1">빠른 시일 내에 답변드리겠습니다.</p>
 43→      </div>
 44→    );
 45→  }
 46→
 47→  return (
 48→    <>
 49→      <h2 className="text-lg font-bold mb-3">문의사항</h2>
 50→      <p className="text-sm text-text-secondary mb-4">
 51→        서비스 이용 중 궁금한 점이나 개선 사항이 있으시면 아래에 남겨주세요.
 52→      </p>
 53→      <textarea
 54→        id="inquiry-message"
 55→        name="message"
 56→        value={message}
 57→        onChange={(e) => setMessage(e.target.value)}
 58→        placeholder="문의 내용을 입력해주세요"
 59→        aria-label="문의 내용"
 60→        className="w-full p-3 rounded-xl border border-border bg-surface text-sm resize-none mb-3"
 61→        rows={3}
 62→      />
 63→      <button
 64→        onClick={handleSubmit}
 65→        disabled={!message.trim() || submitting}
 66→        className="w-full py-2.5 rounded-xl font-semibold text-white bg-primary hover:bg-primary/90 disabled:opacity-40 transition-colors text-sm"
 67→      >
 68→        {submitting ? '전송 중...' : '보내기'}
 69→      </button>
 70→      {submitError && (
 71→        <p className="text-xs text-red-500 mt-2 text-center">
 72→          전송에 실패했습니다. 잠시 후 다시 시도해 주세요.
 73→        </p>
 74→      )}
 75→    </>
 76→  );
 77→}
 78→
 79→const DIFFICULTY_OPTIONS = [
 80→  { value: DIFFICULTY_LEVELS.BEGINNER, label: '입문' },
 81→  { value: DIFFICULTY_LEVELS.ELEMENTARY, label: '초급' },
 82→  { value: DIFFICULTY_LEVELS.INTERMEDIATE, label: '중급' },
 83→];
 84→
 85→export default function Profile() {
 86→  const navigate = useNavigate();
 87→  const { user, settings, setDifficulty, logout } = useUser();
 88→
 89→  return (
 90→    <div className="min-h-screen bg-background pb-24">
 91→      <AppHeader />
 92→
 93→      <main className="container py-6 space-y-6">
 94→        {/* 사용자 정보 */}
 95→        <motion.div
 96→          initial={{ opacity: 0, y: 10 }}
 97→          animate={{ opacity: 1, y: 0 }}
 98→          transition={{ duration: 0.3 }}
 99→          className="card"
100→        >
101→          <h2 className="text-lg font-bold mb-3">프로필</h2>
102→          <div className="space-y-1">
103→            {user?.username && (
104→              <p className="text-text-primary font-medium">{user.username}</p>
105→            )}
106→            {user?.email && (
107→              <p className="text-text-secondary text-sm">{user.email}</p>
108→            )}
109→          </div>
110→        </motion.div>
111→
112→        {/* 난이도 설정 */}
113→        <motion.div
114→          initial={{ opacity: 0, y: 10 }}
115→          animate={{ opacity: 1, y: 0 }}
116→          transition={{ duration: 0.3, delay: 0.1 }}
117→          className="card"
118→        >
119→          <h2 className="text-lg font-bold mb-3">학습 난이도</h2>
120→          <div className="flex gap-2">
121→            {DIFFICULTY_OPTIONS.map((option) => {
122→              const isSelected = settings.difficulty === option.value;
123→              return (
124→                <button
125→                  key={option.value}
126→                  onClick={() => setDifficulty(option.value)}
127→                  className={`flex-1 py-2.5 rounded-lg text-sm font-medium transition-colors ${
128→                    isSelected
129→                      ? 'bg-primary text-white'
130→                      : 'bg-surface border border-border text-text-secondary hover:text-text-primary'
131→                  }`}
132→                >
133→                  {option.label}
134→                </button>
135→              );
136→            })}
137→          </div>
138→        </motion.div>
139→
140→        {/* 로그아웃 버튼 */}
141→        <motion.div
142→          initial={{ opacity: 0, y: 10 }}
143→          animate={{ opacity: 1, y: 0 }}
144→          transition={{ duration: 0.3, delay: 0.2 }}
145→          className="space-y-3"
146→        >
147→          <button
148→            onClick={() => {
149→              logout();
150→              navigate('/auth');
151→            }}
152→            className="btn-secondary w-full"
153→          >
154→            로그아웃
155→          </button>
156→        </motion.div>
157→
158→        {/* 서비스 평가 */}
159→        <motion.div
160→          initial={{ opacity: 0, y: 10 }}
161→          animate={{ opacity: 1, y: 0 }}
162→          transition={{ duration: 0.3, delay: 0.22 }}
163→          className="card cursor-pointer hover:shadow-md transition-shadow"
164→          onClick={() => navigate('/feedback-survey')}
165→        >
