 29→/**
 30→ * SlashCommandMenu - "/" 입력 시 나타나는 슬래시 커맨드 팝업 메뉴
 31→ *
 32→ * @param {string} query - "/" 뒤에 입력된 텍스트 (예: 사용자가 "/ch" 입력 → query = "ch")
 33→ * @param {function} onSelect - 커맨드 선택 시 호출 (command 객체 전달)
 34→ * @param {function} onClose - 메뉴 닫기 시 호출
 35→ * @param {boolean} visible - 메뉴 표시 여부
 36→ */
 37→export default function SlashCommandMenu({ query, onSelect, onClose, visible }) {
 38→  const [activeIndex, setActiveIndex] = useState(0);
 39→  const menuRef = useRef(null);
 40→
 41→  // query로 커맨드 필터링 (cmd, aliases 모두 매칭)
 42→  const filtered = SLASH_COMMANDS.filter((command) => {
 43→    const q = (query || '').toLowerCase();
 44→    if (!q) return true;
 45→    const cmdMatch = command.cmd.slice(1).toLowerCase().startsWith(q);
 46→    const aliasMatch = command.aliases.some((alias) => alias.slice(1).toLowerCase().startsWith(q));
 47→    const descMatch = command.desc.toLowerCase().includes(q);
 48→    return cmdMatch || aliasMatch || descMatch;
 49→  });
 50→
 51→  // query 변경 시 activeIndex 리셋
 52→  useEffect(() => {
 53→    setActiveIndex(0);
 54→  }, [query]);
 55→
 56→  // 키보드 네비게이션 핸들러
 57→  const handleKeyDown = useCallback((e) => {
 58→    if (!visible || filtered.length === 0) return;
 59→
 60→    if (e.key === 'ArrowDown') {
 61→      e.preventDefault();
 62→      setActiveIndex((prev) => (prev + 1) % filtered.length);
 63→    } else if (e.key === 'ArrowUp') {
 64→      e.preventDefault();
 65→      setActiveIndex((prev) => (prev - 1 + filtered.length) % filtered.length);
 66→    } else if (e.key === 'Enter') {
 67→      e.preventDefault();
 68→      onSelect(filtered[activeIndex]);
 69→    } else if (e.key === 'Escape') {
 70→      e.preventDefault();
 71→      onClose();
 72→    }
 73→  }, [visible, filtered, activeIndex, onSelect, onClose]);
 74→
 75→  // 전역 키보드 이벤트 등록
 76→  useEffect(() => {
 77→    if (!visible) return undefined;
 78→    window.addEventListener('keydown', handleKeyDown);
 79→    return () => window.removeEventListener('keydown', handleKeyDown);
 80→  }, [visible, handleKeyDown]);
 81→
 82→  // 활성 아이템 스크롤 보장
 83→  useEffect(() => {
 84→    if (!menuRef.current) return;
 85→    const activeEl = menuRef.current.querySelector('[data-active="true"]');
 86→    if (activeEl) {
 87→      activeEl.scrollIntoView({ block: 'nearest' });
 88→    }
 89→  }, [activeIndex]);
 90→
 91→  if (!visible || filtered.length === 0) return null;
 92→
 93→  return (
 94→    <div
 95→      ref={menuRef}
 96→      className="absolute bottom-full left-0 right-0 z-50 mb-2 overflow-hidden rounded-xl bg-white shadow-lg ring-1 ring-black/5"
 97→      role="listbox"
 98→      aria-label="슬래시 커맨드 목록"
 99→    >
100→      <div className="max-h-[240px] overflow-y-auto py-1">

