23→function parseDateKey(dateKey) {
24→  if (!/^\d{4}-\d{2}-\d{2}$/.test(String(dateKey || ''))) return null;
25→  const [year, month, day] = dateKey.split('-').map(Number);
26→  const date = new Date(Date.UTC(year, month - 1, day));
27→  if (
28→    date.getUTCFullYear() !== year
29→    || date.getUTCMonth() + 1 !== month
30→    || date.getUTCDate() !== day
31→  ) {
32→    return null;
33→  }
34→  return { year, month, day, dateKey: `${year}-${String(month).padStart(2, '0')}-${String(day).padStart(2, '0')}` };
35→}
36→
37→function toDateKeyFromNumber(value) {
38→  const raw = String(value || '').replace(/\D/g, '');
39→  if (raw.length !== 8) return null;
40→  return `${raw.slice(0, 4)}-${raw.slice(4, 6)}-${raw.slice(6, 8)}`;
41→}
