 5→/**
 6→ * 상대 시간 포맷 헬퍼
 7→ * @param {string|null} dateString - ISO 날짜 문자열
 8→ * @returns {string} 한글 상대 시간 표현
 9→ */
10→function formatRelativeTime(dateString) {
11→  if (!dateString) return '';
12→  const now = new Date();
13→  const date = new Date(dateString);
14→  const diffMs = now - date;
15→  const diffMin = Math.floor(diffMs / 60000);
16→  if (diffMin < 1) return '방금 전';
17→  if (diffMin < 60) return `${diffMin}분 전`;
18→  const diffHour = Math.floor(diffMin / 60);
19→  if (diffHour < 24) return `${diffHour}시간 전`;
20→  const diffDay = Math.floor(diffHour / 24);
21→  if (diffDay < 7) return `${diffDay}일 전`;
22→  return date.toLocaleDateString('ko-KR', { month: 'short', day: 'numeric' });
23→}
